from collections import defaultdict

class ResourceAllocationGraph:
    def __init__(self):
        self.processes = set()
        self.resources = set()
        self.assignment_edges = []  # [(process, resource)]
        self.request_edges = []     # [(resource, process)]

    def add_process(self, p):
        self.processes.add(p)

    def add_resource(self, r, instances):
        self.resources.add((r, instances))

    def add_assignment(self, p, r):
        self.assignment_edges.append((p, r))

    def add_request(self, r, p):
        self.request_edges.append((r, p))

    def build_adjacency(self):
        adj = defaultdict(list)
        for p, r in self.assignment_edges:
            adj[p].append(r)
        for r, p in self.request_edges:
            adj[r].append(p)
        return adj

    def has_cycle_dfs(self, node, visited, rec_stack, adj):
        visited.add(node)
        rec_stack.add(node)

        for neighbor in adj[node]:
            if neighbor not in visited:
                if self.has_cycle_dfs(neighbor, visited, rec_stack, adj):
                    return True
            elif neighbor in rec_stack:
                return True

        rec_stack.remove(node)
        return False

    def detect_deadlock(self):
        adj = self.build_adjacency()
        all_nodes = list(self.processes | {r[0] for r in self.resources})

        visited = set()
        for node in all_nodes:
            if node not in visited:
                if self.has_cycle_dfs(node, visited, set(), adj):
                    return True, "Deadlock detected - cycle exists in RAG"
        return False, "No deadlock"

