rag = ResourceAllocationGraph()
rag.add_process("P1")
rag.add_process("P2")
rag.add_resource("R1", 1)
rag.add_resource("R2", 1)
rag.add_assignment("P1", "R1")
rag.add_assignment("P2", "R2")
rag.add_request("R2", "P1")
rag.add_request("R1", "P2")

