#include <stdio.h>
#include <stdbool.h>

#define NUM_PROCESSES 5
#define NUM_RESOURCES 3

int available[NUM_RESOURCES];
int maximum[NUM_PROCESSES][NUM_RESOURCES];
int allocation[NUM_PROCESSES][NUM_RESOURCES];
int need[NUM_PROCESSES][NUM_RESOURCES];

void calculate_need() {
    for (int i = 0; i < NUM_PROCESSES; i++)
        for (int j = 0; j < NUM_RESOURCES; j++)
            need[i][j] = maximum[i][j] - allocation[i][j];
}

bool is_safe() {
    int work[NUM_RESOURCES];
    bool finish[NUM_PROCESSES] = {false};

    for (int j = 0; j < NUM_RESOURCES; j++)
        work[j] = available[j];

    int count = 0;
    while (count < NUM_PROCESSES) {
        bool found = false;
        for (int i = 0; i < NUM_PROCESSES; i++) {
            if (!finish[i]) {
                bool can_allocate = true;
                for (int j = 0; j < NUM_RESOURCES; j++) {
                    if (need[i][j] > work[j]) {
                        can_allocate = false;
                        break;
                    }
                }
                if (can_allocate) {
                    for (int j = 0; j < NUM_RESOURCES; j++)
                        work[j] += allocation[i][j];
                    finish[i] = true;
                    found = true;
                    count++;
                }
            }
        }
        if (!found) return false;
    }
    return true;
}

bool request_resources(int process_id, int request[]) {
    for (int j = 0; j < NUM_RESOURCES; j++) {
        if (request[j] > need[process_id][j])
            return false;
        if (request[j] > available[j])
            return false;
    }

    for (int j = 0; j < NUM_RESOURCES; j++) {
        available[j] -= request[j];
        allocation[process_id][j] += request[j];
        need[process_id][j] -= request[j];
    }

    if (is_safe()) {
        return true;
    } else {
        for (int j = 0; j < NUM_RESOURCES; j++) {
            available[j] += request[j];
            allocation[process_id][j] -= request[j];
            need[process_id][j] += request[j];
        }
        return false;
    }
}

int main() {
    // Initialize: available[3] = {3, 3, 2}
    // maximum and allocation matrices...
    // Check if system is in safe state
    if (is_safe())
        printf("System is in SAFE state\n");
    else
        printf("System is in UNSAFE state\n");
    return 0;
}
